import React, { useState } from "react";
import { BrowserRouter as Router, Routes, Route, Link } from "react-router-dom";
import "./App.css";
import LoginModal from "./components/Login";
import RegisterModal from "./components/Register";

// Pages
import Home from "./pages/Home";
import Medicine from "./pages/Medicine";
import Consultancy from "./pages/Consultancy";
import Pathology from "./pages/Pathology";
import BloodBank from "./pages/BloodBank";

function App() {
  const [showLogin, setShowLogin] = useState(false);
  const [showRegister, setShowRegister] = useState(false);

  return (
    <Router>
      <div className="app">
        {/* Header */}
        <header className="header">
          <h1>HEALink</h1>
          <nav>
            <ul>
              <li><Link to="/">Home</Link></li>
              <li><Link to="/pathology">Pathology</Link></li>
              <li><Link to="/blood-bank">Blood Bank</Link></li>
              <li><Link to="/consultancy">Consultancy</Link></li>
              <li><Link to="/medicine">Medicine</Link></li>
            </ul>
          </nav>
          <div className="auth-buttons">
            <button className="login-btn" onClick={() => setShowLogin(true)}>Login</button>
            <button className="register-btn" onClick={() => setShowRegister(true)}>Register</button>
          </div>
        </header>

        {/* Page Routes */}
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/medicine" element={<Medicine />} />
          <Route path="/consultancy" element={<Consultancy />} />
          <Route path="/pathology" element={<Pathology />} />
          <Route path="/blood-bank" element={<BloodBank />} />
        </Routes>

        {/* Footer */}
        <footer className="footer">
          <p>© 2025 HEALink. All rights reserved.</p>
        </footer>

        {/* Modals */}
        {showLogin && <LoginModal onClose={() => setShowLogin(false)} />}
        {showRegister && <RegisterModal onClose={() => setShowRegister(false)} />}
      </div>
    </Router>
  );
}

export default App;
